CREATE VIEW [SalesLT].[vProductModelCatalogDescription]
AS
SELECT
    [ProductModelID]
    ,[Name]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        declare namespace html="http://www.w3.org/1999/xhtml";
        (/p1:ProductDescription/p1:Summary/html:p)[1]', 'nvarchar(max)') AS [Summary]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        (/p1:ProductDescription/p1:Manufacturer/p1:Name)[1]', 'nvarchar(max)') AS [Manufacturer]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        (/p1:ProductDescription/p1:Manufacturer/p1:Copyright)[1]', 'nvarchar(30)') AS [Copyright]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        (/p1:ProductDescription/p1:Manufacturer/p1:ProductURL)[1]', 'nvarchar(256)') AS [ProductURL]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        declare namespace wm="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelWarrAndMain";
        (/p1:ProductDescription/p1:Features/wm:Warranty/wm:WarrantyPeriod)[1]', 'nvarchar(256)') AS [WarrantyPeriod]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        declare namespace wm="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelWarrAndMain";
        (/p1:ProductDescription/p1:Features/wm:Warranty/wm:Description)[1]', 'nvarchar(256)') AS [WarrantyDescription]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        declare namespace wm="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelWarrAndMain";
        (/p1:ProductDescription/p1:Features/wm:Maintenance/wm:NoOfYears)[1]', 'nvarchar(256)') AS [NoOfYears]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        declare namespace wm="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelWarrAndMain";
        (/p1:ProductDescription/p1:Features/wm:Maintenance/wm:Description)[1]', 'nvarchar(256)') AS [MaintenanceDescription]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        declare namespace wf="http://www.adventure-works.com/schemas/OtherFeatures";
        (/p1:ProductDescription/p1:Features/wf:wheel)[1]', 'nvarchar(256)') AS [Wheel]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        declare namespace wf="http://www.adventure-works.com/schemas/OtherFeatures";
        (/p1:ProductDescription/p1:Features/wf:saddle)[1]', 'nvarchar(256)') AS [Saddle]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        declare namespace wf="http://www.adventure-works.com/schemas/OtherFeatures";
        (/p1:ProductDescription/p1:Features/wf:pedal)[1]', 'nvarchar(256)') AS [Pedal]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        declare namespace wf="http://www.adventure-works.com/schemas/OtherFeatures";
        (/p1:ProductDescription/p1:Features/wf:BikeFrame)[1]', 'nvarchar(max)') AS [BikeFrame]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        declare namespace wf="http://www.adventure-works.com/schemas/OtherFeatures";
        (/p1:ProductDescription/p1:Features/wf:crankset)[1]', 'nvarchar(256)') AS [Crankset]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        (/p1:ProductDescription/p1:Picture/p1:Angle)[1]', 'nvarchar(256)') AS [PictureAngle]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        (/p1:ProductDescription/p1:Picture/p1:Size)[1]', 'nvarchar(256)') AS [PictureSize]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        (/p1:ProductDescription/p1:Picture/p1:ProductPhotoID)[1]', 'nvarchar(256)') AS [ProductPhotoID]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        (/p1:ProductDescription/p1:Specifications/Material)[1]', 'nvarchar(256)') AS [Material]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        (/p1:ProductDescription/p1:Specifications/Color)[1]', 'nvarchar(256)') AS [Color]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        (/p1:ProductDescription/p1:Specifications/ProductLine)[1]', 'nvarchar(256)') AS [ProductLine]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        (/p1:ProductDescription/p1:Specifications/Style)[1]', 'nvarchar(256)') AS [Style]
    ,[CatalogDescription].value(N'declare namespace p1="http://schemas.microsoft.com/sqlserver/2004/07/adventure-works/ProductModelDescription";
        (/p1:ProductDescription/p1:Specifications/RiderExperience)[1]', 'nvarchar(1024)') AS [RiderExperience]
    ,[rowguid]
    ,[ModifiedDate]
FROM [SalesLT].[ProductModel]
WHERE [CatalogDescription] IS NOT NULL;

procedures.definition:
/* Insert records in SalesLT_Silver.SalesFact */

CREATE   PROCEDURE SalesLT_Silver.usp_InsertSalesFact
(
    @SalesOrderID INT,
    @SalesOrderDetailID INT,
    @SalesOrderNumber NVARCHAR(25),
    @CustomerID INT,
    @ProductID INT,
    @OrderDate DATE,
    @ShipDate DATE = NULL,
    @OrderQty INT,
    @UnitPrice DECIMAL(19,4),
    @UnitPriceDiscount DECIMAL(19,4),
    @LineTotal DECIMAL(19,4),
    @TotalDue DECIMAL(19,4),
    @TaxAmt DECIMAL(19,4),
    @Freight DECIMAL(19,4),
    @SourceSystemID INT = 1
)
AS
BEGIN
    SET NOCOUNT ON;

    INSERT INTO SalesLT_Silver.SalesFact
    (
        SalesOrderID,
        SalesOrderDetailID,
        SalesOrderNumber,
        CustomerID,
        ProductID,
        OrderDate,
        ShipDate,
        OrderYear,
        OrderMonth,
        OrderQuarter,
        DaysToShip,
        OrderQty,
        UnitPrice,
        UnitPriceDiscount,
        LineTotal,
        DiscountPct,
        TotalDue,
        TaxAmt,
        Freight,
        LoadDate,
        ModifiedDate,
        SourceSystemID
    )
    VALUES
    (
        @SalesOrderID,
        @SalesOrderDetailID,
        @SalesOrderNumber,
        @CustomerID,
        @ProductID,
        @OrderDate,
        @ShipDate,
        YEAR(@OrderDate),
        MONTH(@OrderDate),
        DATEPART(QUARTER, @OrderDate),
        CASE WHEN @ShipDate IS NOT NULL THEN DATEDIFF(DAY, @OrderDate, @ShipDate) ELSE NULL END,
        @OrderQty,
        @UnitPrice,
        @UnitPriceDiscount,
        @LineTotal,
        CASE WHEN @UnitPrice > 0 THEN (@UnitPriceDiscount / @UnitPrice) * 100 ELSE 0 END,
        @TotalDue,
        @TaxAmt,
        @Freight,
        GETDATE(),
        GETDATE(),
        @SourceSystemID
    );
END;

CREATE PROCEDURE SalesLT_Silver.usp_UpsertCustomer
    @CustomerID INT,
    @FirstName NVARCHAR(50),
    @MiddleName NVARCHAR(50) = NULL,
    @LastName NVARCHAR(50),
    @EmailAddress NVARCHAR(50) = NULL,
    @Phone NVARCHAR(25) = NULL,
    @CompanyName NVARCHAR(128) = NULL,
    @IsActive BIT = 1,
    @SourceSystemID INT = 1
AS
BEGIN
    SET NOCOUNT ON;

    IF EXISTS (SELECT 1 FROM SalesLT_Silver.CustomerMaster WHERE CustomerID = @CustomerID)
    BEGIN
        -- Update existing customer
        UPDATE SalesLT_Silver.CustomerMaster
        SET 
            FirstName = @FirstName,
            MiddleName = @MiddleName,
            LastName = @LastName,
            FullName = RTRIM(LTRIM(ISNULL(@FirstName,'') + ' ' + ISNULL(@MiddleName,'') + ' ' + ISNULL(@LastName,''))),
            EmailAddress = @EmailAddress,
            Phone = @Phone,
            CompanyName = @CompanyName,
            IsActive = @IsActive,
            ModifiedDate = GETDATE(),
            SourceSystemID = @SourceSystemID
        WHERE CustomerID = @CustomerID;
    END
    ELSE
    BEGIN
        -- Insert new customer
        INSERT INTO SalesLT_Silver.CustomerMaster
            (CustomerID, FirstName, MiddleName, LastName, FullName, EmailAddress, Phone, CompanyName, IsActive, LoadDate, ModifiedDate, SourceSystemID)
        VALUES
            (@CustomerID, @FirstName, @MiddleName, @LastName, 
             RTRIM(LTRIM(ISNULL(@FirstName,'') + ' ' + ISNULL(@MiddleName,'') + ' ' + ISNULL(@LastName,''))),
             @EmailAddress, @Phone, @CompanyName, @IsActive, GETDATE(), GETDATE(), @SourceSystemID);
    END
END;
